ruleContent.payAction:
var arr = baseUrl.match(/bookId=(\d+)/);
var bid = arr ? arr[1] : "";

let chapterMatch = baseUrl.match(/chapterId=(\d+)/i);

 let chapterid = chapterMatch ? chapterMatch[1] : "";

let bookid = bid;

 let token = source.get("cdkey");

let pg = source.getVariable();

let pz = 15;
let cursorid = "0";

function loadPage(pg) {
    let url = "http://101.200.42.234:15380/chapterreviewparagraph?bookid=" + bookid
        + "&chapterid=" + chapterid
        + "&pg=" + pg
        + "&pz=" + pz
        + "&cursorid=" + cursorid
        + "&token=" + token;

    let res = java.ajax(url);
    return JSON.parse(res);
}


let json = loadPage(pg);

let commentHTML = '';

function cleanContent(str) {
    return (str || '').replace(/\[fn=\d+\]/g, '').trim();
}

let moreSegs = json.Data.ParagraphsInfos || [];
for (let seg of moreSegs) {
    let list = seg.DataList || [];
    let quote = list[0]?.RefferContent || "段落评论";

    let blockImgHtml = "";
    if (seg.BlockImgUrl) {
        blockImgHtml = `<img src="${seg.BlockImgUrl}" class="chapter-img" style="max-width:100%;border-radius:8px;margin:8px 0;display:block;">`;
    }

    commentHTML += `
    <div class="segment">
        <div class="quote">${quote}</div>
        ${blockImgHtml}`;

    for (let c of list) {
        if (!c.Id) continue;
        let avatar = c.UserHeadIcon || '';
        let name = c.UserName || '匿名';
        let ip = c.IpLocation ? `(${c.IpLocation})` : '';
        let content = cleanContent(c.Content);
        let isReply = c.IsReplyReview === 1 || c.RefferCommentId > 0;
        let style = isReply ? "margin-left:24px;" : "";

        commentHTML += `
        <div class="comment" style="${style}">
            <img class="avatar" src="${avatar}">
            <div class="comment-body">
                <div class="name">${name} ${ip}</div>
                <div class="content">${content}</div>
            </div>
        </div>`;
    }
    commentHTML += '</div><div class="split"></div>';
}

commentHTML += `
<div style="text-align:center;margin:30px 0;color:#888;">
    当前第 ${pg} 页
</div>`;


let html = `
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>第${pg}页-本章说</title>
<style>
body{background:#1e1e1e;color:#fff;padding:16px;font-size:16px;line-height:1.6}
.comment{display:flex;gap:10px;background:#2b2b2b;padding:12px 14px;border-radius:8px;margin-bottom:10px;align-items:flex-start}
.avatar{width:40px;height:40px;border-radius:50%;object-fit:cover;flex-shrink:0}
.comment-body{flex:1}
.name{color:#60d9ff;font-weight:bold}
.content{margin-top:4px}
.segment{margin-bottom:10px}
.quote{background:#333;color:#bbb;padding:10px 14px;border-left:3px solid #777;border-radius:6px;margin-bottom:10px}
.split{height:1px;background:#444;margin:20px 0}
.chapter-img{max-width:100%;border-radius:8px;margin:8px 0;display:block}
</style>
</head>
<body>${commentHTML}</body>
</html>`;

let url = "data:text/html;base64," + java.base64Encode(html);
java.startBrowser(url, "本章说");

